const _Triangle = function Triangle() {
  class Triangle {
    constructor(...sides) {
      this.sides = sides;
      const [a, b, c] = sides;
      this._valid = a > 0 && b > 0 && c > 0 &&
        a + b >= c && b + c >= a && a + c >= b;
    }

    get isEquilateral() {
      if (!this._valid) return false;
      const [a, b, c] = this.sides;
      return a === b && b === c;
    }

    get isIsosceles() {
      if (!this._valid) return false;
      const [a, b, c] = this.sides;
      return a === b || b === c || a === c;
    }

    get isScalene() {
      if (!this._valid) return false;
      const [a, b, c] = this.sides;
      return a !== b && b !== c && a !== c;
    }
  }

  return Triangle;
};

